#include <bits/stdc++.h>
using namespace std;
const int N=2e5+5,mod=1e9+7;
int n,m,nxt[N],pre[N],f[N],sum;
long long ans=1;
int father(int x){
	if(f[x]!=x)
		f[x]=father(f[x]);
	return f[x];
}
void merge(int x,int y){
	int fx=father(x),fy=father(y);
	if(fx!=fy)
		f[fy]=fx,sum--;
}
int main(){
	scanf("%d%d",&n,&m);
	sum=n;
	for(int i=1;i<=n;i++)
		f[i]=i;
	for(int i=1;i<=m;i++){
		int a,b;
		scanf("%d%d",&a,&b);
		if(nxt[a]==b && pre[b]==a)
			continue;
		if((pre[b]>0 && pre[b]!=a) || (nxt[a]>0 && nxt[a]!=b) || father(a)==father(b)){
			printf("0");
			return 0;
		}
		nxt[a]=b,pre[b]=a;
		merge(a,b);
	}
	for(int i=1;i<=sum;i++)
		ans*=i,ans%=mod;
	printf("%lld",ans);
	return 0;
}
